<script setup>
import { ref, computed, onMounted, onUnmounted, watch, nextTick } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { getWorkImageUrl } from '@/config/api'
import { fetchSeriesDetail } from '@/api/creatorApi'
import gsap from 'gsap'

// ═══════════════════════════════════════════════════════════════
// GalleryViewer — 合集作品预览页面
//
// 两种模式：
//   合集模式 — 传入 seriesId（props 或 route query），自动加载合集内所有作品
//   单图模式 — 传入 imagePath，仅展示单张图片（向后兼容）
//
// 分层结构：
//   Layer 1 底层 — 全屏毛玻璃模糊背景（当前预览原图铺满 + blur）
//   Layer 2 中层 — 居中预览卡片（大圆角 + 大面积外阴影 + 清晰原图）
//   Layer 3 底层 — 底部导航控件栏（药丸胶囊 #0a0a0a）
//   Top-left — 两个黑色药丸（Pixel Vision 品牌 + 返回按钮）
// ═══════════════════════════════════════════════════════════════

const route = useRoute()
const router = useRouter()

// ── Props ──────────────────────────────────────────────────────
const props = defineProps({
  seriesId: { type: [Number, String], default: null },
  imagePath: { type: String, default: '' },
  workTitle: { type: String, default: '未命名作品' },
})

const emit = defineEmits(['prev', 'next', 'close'])

// ── Refs ───────────────────────────────────────────────────────
const containerRef = ref(null)
const cardRef = ref(null)
const navRef = ref(null)
const topLeftRef = ref(null)
const bgRef = ref(null)

// ═══════════════════════════════════════════════════════════════
// 合集模式 — 加载合集内所有作品
// ═══════════════════════════════════════════════════════════════
const resolvedSeriesId = computed(() => {
  if (props.seriesId) return Number(props.seriesId)
  if (route.query.seriesId) return Number(route.query.seriesId)
  return null
})

const works = ref([])
const currentIndex = ref(0)
const seriesLoading = ref(false)
const loadError = ref('')

const loadSeriesWorks = async () => {
  const sid = resolvedSeriesId.value
  if (!sid) return

  seriesLoading.value = true
  loadError.value = ''

  try {
    const result = await fetchSeriesDetail(sid)
    if (result.success && result.data) {
      works.value = (result.data.records || []).map(w => ({
        id: w.work_id,
        title: w.work_title || '未命名作品',
        imgUrl: w.imgFullUrl || '',
        thumbUrl: w.thumbFullUrl || '',
      }))
      currentIndex.value = 0
    } else {
      loadError.value = result.message || '加载合集失败'
    }
  } catch {
    loadError.value = '网络错误，请稍后重试'
  }

  seriesLoading.value = false
}

// ═══════════════════════════════════════════════════════════════
// 当前作品 / 图片 / 标题
// ═══════════════════════════════════════════════════════════════
const currentWork = computed(() => works.value[currentIndex.value] || null)

const currentImage = computed(() => {
  if (currentWork.value) return currentWork.value.imgUrl || ''
  // 单图模式兜底
  if (props.imagePath) {
    return props.imagePath.startsWith('http') ? props.imagePath : getWorkImageUrl(props.imagePath)
  }
  return ''
})

const currentTitle = computed(() => {
  if (currentWork.value) return currentWork.value.title
  return props.workTitle || route.query.title || '未命名作品'
})

const totalCount = computed(() => works.value.length)

const bgStyle = computed(() => ({
  backgroundImage: currentImage.value ? `url(${currentImage.value})` : 'none',
}))

// ═══════════════════════════════════════════════════════════════
// 导航状态
// ═══════════════════════════════════════════════════════════════
const canGoPrev = computed(() => works.value.length > 0 && currentIndex.value > 0)
const canGoNext = computed(() => works.value.length > 0 && currentIndex.value < works.value.length - 1)

const goPrev = () => {
  if (!canGoPrev.value) return
  currentIndex.value--
  emit('prev')
}

const goNext = () => {
  if (!canGoNext.value) return
  currentIndex.value++
  emit('next')
}

// ═══════════════════════════════════════════════════════════════
// GSAP 动画
// ═══════════════════════════════════════════════════════════════
let ctx = null

const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches

onMounted(async () => {
  // 合集模式 → 加载作品列表
  if (resolvedSeriesId.value) {
    await loadSeriesWorks()
  }

  if (prefersReduced) return

  ctx = gsap.context(() => {
    const tl = gsap.timeline({ defaults: { ease: 'power2.out' } })

    tl.fromTo(bgRef.value,
      { opacity: 0 },
      { opacity: 1, duration: 0.5 },
      0
    )
    .fromTo(cardRef.value,
      { scale: 0.92, opacity: 0 },
      { scale: 1, opacity: 1, duration: 0.5, ease: 'expo.out' },
      0.08
    )
    .fromTo(topLeftRef.value,
      { opacity: 0, y: -12 },
      { opacity: 1, y: 0, duration: 0.4 },
      0.12
    )
    .fromTo(navRef.value,
      { opacity: 0, y: 20 },
      { opacity: 1, y: 0, duration: 0.45 },
      0.18
    )
  }, containerRef.value)
})

// 切换图片时的卡片过渡动画
watch(currentIndex, () => {
  if (prefersReduced || !cardRef.value) return
  nextTick(() => {
    gsap.fromTo(cardRef.value,
      { opacity: 0, scale: 0.97 },
      { opacity: 1, scale: 1, duration: 0.3, ease: 'power2.out' }
    )
  })
})

onUnmounted(() => {
  if (ctx) {
    ctx.revert()
    ctx = null
  }
})

// ── Handlers ───────────────────────────────────────────────────
const handleClose = () => {
  emit('close')
  if (window.history.length > 1) {
    router.back()
  }
}
</script>

<template>
  <div class="gallery-viewer" ref="containerRef">

    <!-- ═══════════════════════════════════════════════════════
         Layer 1 — 底层全屏背景
         当前预览原图铺满视口 + 重度毛玻璃模糊 + 暗化
         ═══════════════════════════════════════════════════════ -->
    <div class="gallery-bg" ref="bgRef" :style="bgStyle" aria-hidden="true">
      <div class="gallery-bg--blur"></div>
    </div>

    <!-- ═══════════════════════════════════════════════════════
         Layer 2 — 中层预览卡片
         ═══════════════════════════════════════════════════════ -->
    <div class="gallery-card" ref="cardRef">
      <div class="gallery-card--inner">
        <!-- 合集加载中 -->
        <div v-if="seriesLoading" class="gallery-card--placeholder">
          <div class="gallery-card--spinner"></div>
          <span class="gallery-card--loading-text">加载中...</span>
        </div>
        <!-- 加载失败 -->
        <div v-else-if="loadError" class="gallery-card--placeholder">
          <svg viewBox="0 0 24 24" width="48" height="48" fill="none" stroke="var(--color-danger)" stroke-width="1" stroke-linecap="round">
            <circle cx="12" cy="12" r="10"/>
            <line x1="15" y1="9" x2="9" y2="15"/>
            <line x1="9" y1="9" x2="15" y2="15"/>
          </svg>
          <span class="gallery-card--error-text">{{ loadError }}</span>
        </div>
        <!-- 合集为空 -->
        <div v-else-if="resolvedSeriesId && !seriesLoading && works.length === 0 && !loadError" class="gallery-card--placeholder">
          <svg viewBox="0 0 24 24" width="48" height="48" fill="none" stroke="var(--text-muted)" stroke-width="1" stroke-linecap="round">
            <rect x="3" y="3" width="18" height="18" rx="2" ry="2"/>
            <circle cx="8.5" cy="8.5" r="1.5"/>
            <polyline points="21 15 16 10 5 21"/>
          </svg>
          <span class="gallery-card--empty-text">该合集暂无作品</span>
        </div>
        <!-- 图片展示 -->
        <img
          v-else-if="currentImage"
          :src="currentImage"
          :alt="currentTitle"
          class="gallery-card--img"
          draggable="false"
        />
        <!-- 单图模式无图片 -->
        <div v-else class="gallery-card--placeholder">
          <svg viewBox="0 0 24 24" width="48" height="48" fill="none" stroke="var(--text-muted)" stroke-width="1" stroke-linecap="round">
            <rect x="3" y="3" width="18" height="18" rx="2" ry="2"/>
            <circle cx="8.5" cy="8.5" r="1.5"/>
            <polyline points="21 15 16 10 5 21"/>
          </svg>
        </div>
      </div>
    </div>

    <!-- ═══════════════════════════════════════════════════════
         Top-Left — 两个黑色药丸
         Pill 1: Pixel Vision 品牌（照搬 NavBar 标题 + 三枚 SVG）
         Pill 2: 返回按钮（白色 SVG，hover → 主题绿）
         ═══════════════════════════════════════════════════════ -->
    <div class="gallery-top-left" ref="topLeftRef">

      <!-- Pill 1 — Pixel Vision 品牌药丸 -->
      <div class="pill pill-brand" aria-label="Pixel Vision">
        <p class="pill-brand--text">Pixel - Vision</p>
        <svg class="pill-brand--svg pill-brand--svg1" t="1779498952979" viewBox="0 0 1024 1024" version="1.1" xmlns="http://www.w3.org/2000/svg" p-id="3588" width="16" height="16"><path d="M427.20768 958.73536s137.42592-16.76288 194.80576-106.79808c18.49856-29.02016 39.61856-43.69408 60.33408-44.68736 58.33216-2.80576 35.24096 55.38304 40.29952 62.27968 4.29056 5.85216 13.93664 2.56 34.0992 6.22592 23.04 4.20352 34.33984 46.592-0.83968 73.25184-41.05728 31.09888-168.56064 99.44064-328.69888 9.728z" fill="#B8D390"/><path d="M127.4368 651.5456s-11.776-76.43648 86.79936-105.8816c20.40832 29.61408 16.6144 75.776 3.0976 108.99456-9.56928 23.552-26.16832 37.376-34.0992 40.48384-14.66368 6.26176-1.536 12.68736 15.49824 9.33888a196.44416 196.44416 0 0 0 65.1008-31.13984c16.85504-9.728 16.75264 17.12128 12.40064 37.376s-39.66976 60.53376-102.30272 40.48384c0 0-16.70144-6.25664-6.20032 9.33888s21.87776 60.35456-55.808 65.39776c0 0 4.31616-21.03808-27.89888-52.9408s1.88928-59.904 18.60096-52.9408c0 0 5.24288 1.29536 0-6.22592-4.33152-6.18496-48.04608-0.41984-71.30112-18.68288-14.25408-11.19744-23.41376-38.2208-24.10496-45.68064-3.83488-41.5488 17.88928-13.48096 17.92-13.48608s37.15584 26.91072 49.60256 28.02688 7.72608-2.87232 3.0976-6.23104S0.55296 610.92864 22.016 530.09408c96.96256-6.28736 99.2 112.128 99.2 112.128s3.62496 19.34336 6.2208 9.32352z" fill="#77B26B"/><path d="M332.03712 424.2176s67.00544 73.50272 55.808 143.24736c-8.96512 55.7824-64.6912 57.344-80.59904 68.51072-10.80832 7.59808-34.27328-39.59808-27.68896-92.16a126.83776 126.83776 0 0 1 33.88928-72.86272s3.93216-4.02432 6.20032 3.11296a275.36896 275.36896 0 0 1 6.20032 37.376c0.58368 3.98848 2.2016 13.51168 6.20032 15.56992 2.34496 0.2304 6.39488-6.74304 6.20032-12.45696-0.13824-4.096-0.768-21.66784-3.10272-40.48384-3.18976-25.69728-7.85408-53.4016-3.10784-49.85344z" fill="#6D8638"/><path d="M139.83744 277.85728s16.77824-59.74528 68.1984-40.48384c36.41344 13.62432 25.05216 57.344 24.80128 71.62368 0 0 74.6752-