<style scoped>
/* ═══════════════════════════════════════════════════════════════
   GalleryViewer — 分层视觉样式
   ═══════════════════════════════════════════════════════════════ */

.gallery-viewer {
  position: fixed;
  inset: 0;
  z-index: 2000;
  background: var(--bg-primary);
  overflow: hidden;
}

/* ── Layer 1: 底层全屏模糊背景 ──────────────────────────────── */
.gallery-bg {
  position: absolute;
  inset: -40px; /* 扩展防止模糊边缘露出黑边 */
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  z-index: 0;
}

.gallery-bg--blur {
  position: absolute;
  inset: 0;
  background: inherit;
  background-size: cover;
  background-position: center;
  filter: blur(64px) brightness(0.35) saturate(0.6);
  transform: scale(1.05);
}

/* ── Layer 2: 中层预览卡片 ──────────────────────────────────── */
.gallery-card {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  z-index: 1;
  max-width: 82vw;
  max-height: 74vh;
  border-radius: 24px;
  overflow: hidden;
  background: rgba(10, 10, 10, 0.25);
  box-shadow:
    0 0 0 1px rgba(255, 255, 255, 0.04),
    0 32px 96px rgba(0, 0, 0, 0.65),
    0 12px 40px rgba(0, 0, 0, 0.45),
    0 4px 12px rgba(0, 0, 0, 0.3);
  user-select: none;
}

.gallery-card--inner {
  display: flex;
  align-items: center;
  justify-content: center;
  min-width: 120px;
  min-height: 120px;
}

.gallery-card--img {
  display: block;
  max-width: 82vw;
  max-height: 74vh;
  object-fit: contain;
  -webkit-user-drag: none;
}

.gallery-card--placeholder {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 16px;
  width: 280px;
  min-height: 240px;
  opacity: 0.6;
}

.gallery-card--spinner {
  width: 32px;
  height: 32px;
  border: 2px solid rgba(255, 255, 255, 0.1);
  border-top-color: var(--color-primary);
  border-radius: 50%;
  animation: gv-spin 0.8s linear infinite;
}

@keyframes gv-spin {
  to { transform: rotate(360deg); }
}

.gallery-card--loading-text,
.gallery-card--error-text,
.gallery-card--empty-text {
  color: var(--text-secondary);
  font-size: 13px;
  text-align: center;
}

.gallery-card--error-text {
  color: var(--color-danger);
}

/* ── Top-Left: 黑色药丸 ────────────────────────────────────── */
.gallery-top-left {
  position: absolute;
  top: 24px;
  left: 24px;
  z-index: 2;
  display: flex;
  align-items: center;
  gap: 12px;
}

.pill {
  width: 160px;
  height: 40px;
  border-radius: 999px;
  background: #0a0a0a;
  display: flex;
  align-items: center;
  border: none;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.4);
  display: flex;
  justify-content: center;
  align-items: center;  
}

/* Pill 1 — Pixel Vision 品牌药丸 */
.pill-brand {
  position: relative;
  cursor: default;
  gap: 4px;
}

.pill-brand--text {
  margin: 0;
  font-family: "华文琥珀", sans-serif;
  font-size: 18px;
  line-height: 40px;
  white-space: nowrap;
  background: linear-gradient(to right, #19b859 0%, #6EC597 49.5%, #fff 50.5%, #fff 100%);
  background-size: 200% 100%;
  background-position-x: 100%;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  position: relative;
  z-index: 2;
}

.pill-brand--svg {
  position: absolute;
  z-index: 1;
}

.pill-brand--svg1 {
  top: 11px;
  left: 17px;
}

.pill-brand--svg2 {
  top: 6px;
  left: 64px;
  z-index: 3;
}

.pill-brand--svg3 {
  top: 12px;
  left: 122px;
}

/* Pill 2 — 返回按钮 */
.pill-back {
  width: 40px;
  padding: 0;
  justify-content: center;
  cursor: pointer;
  color: #ffffff;
  transition: color 0.25s ease;
}

.pill-back:hover {
  color: var(--color-primary);
}

/* ── Layer 3: 底部导航控件栏 ───────────────────────────────── */
.gallery-nav {
  position: absolute;
  bottom: 40px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 2;
  display: flex;
  align-items: center;
  height: 48px;
  padding: 0 8px;
  border-radius: 999px;
  background: #0a0a0a;
  box-shadow:
    0 8px 32px rgba(0, 0, 0, 0.55),
    inset 0 1px 0 rgba(255, 255, 255, 0.04);
  min-width: 360px;
  max-width: 90vw;
}

.nav-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  height: 34px;
  padding: 0 16px;
  border-radius: 999px;
  border: none;
  background: transparent;
  color: var(--text-secondary);
  font-size: 13px;
  cursor: pointer;
  transition: color 0.2s ease, background 0.2s ease;
  white-space: nowrap;
  flex-shrink: 0;
}

.nav-btn:hover:not(.nav-btn--disabled) {
  color: var(--text-primary);
  background: rgba(255, 255, 255, 0.06);
}

.nav-btn--disabled {
  opacity: 0.25;
  cursor: default;
}

.nav-title {
  flex: 1;
  text-align: center;
  color: var(--text-primary);
  font-size: 14px;
  font-weight: 500;
  line-height: 1.4;
